import { readFileSync } from "node:fs";
import { join } from "node:path";
import { describe, expect, it } from "vitest";
import { isValidStudioRoute } from "./studioRoutes.js";
describe("isValidStudioRoute", () => {
    const allowed = [
        "/studio",
        "/studio/experiments",
        "/studio/close",
        "/studio/trace-plan/abc-123",
        // Legacy back-compat: old plugin versions still navigate to
        // /datasets/labeled (matched as a dataset-id segment; the server
        // redirects it). Must stay allowed while those versions are in the wild.
        "/studio/trace-functions/fn-1/datasets/labeled",
        "/studio/trace-functions/fn-1/datasets/ds-2",
        "/studio/trace-functions/fn-1/template-preview",
        "/studio/trace-functions/fn-1/template-preview/tpl-3",
        "/studio/sign-in",
        "/studio/experiments?testRunIds=a,b,c",
        "/studio/trace-functions/fn-1/datasets/labeled?foo=bar",
    ];
    for (const route of allowed) {
        it(`allows ${route}`, () => {
            expect(isValidStudioRoute(route)).toBe(true);
        });
    }
    const blocked = [
        "/studio/admin",
        "/studio/trace-plan",
        "/studio/trace-plan/abc/extra",
        "/traces",
        "/",
        "/studio/trace-functions",
        "/studio/trace-functions/fn-1",
        "/studio/trace-functions/fn-1/datasets",
        "/studio/trace-functions/fn-1/datasets/labeled/extra",
        "/studio/trace-functions/fn-1?foo=bar",
    ];
    for (const route of blocked) {
        it(`blocks ${route}`, () => {
            expect(isValidStudioRoute(route)).toBe(false);
        });
    }
});
describe("STUDIO_ROUTE_PATTERNS parity with bitfab-web", () => {
    it("matches the server-side whitelist exactly", () => {
        const clientFile = readFileSync(join(__dirname, "studioRoutes.ts"), "utf8");
        const serverFile = readFileSync(join(__dirname, "../../bitfab-web/src/app/studio/studioRoutes.ts"), "utf8");
        expect(clientFile).toBe(serverFile);
    });
});
